code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, icon } from 'decantr/components';

code.example:
function UserMessage({ message, onEdit, onDelete }) {
  const { div, span, time } = tags;
  const [showActions, setShowActions] = createSignal(false);

  return div({ 
    class: css('_flex _jce _gap3 _py2'),
    onmouseenter: () => setShowActions(true),
    onmouseleave: () => setShowActions(false)
  },
    showActions() ? div({ class: css('_flex _gap1 _aic') },
      Button({ variant: 'ghost', size: 'xs', onclick: onEdit }, icon('edit', { size: '14' })),
      Button({ variant: 'ghost', size: 'xs', onclick: onDelete }, icon('trash', { size: '14' }))
    ) : null,
    div({ class: css('_flex _col _gap1 _maxw[70%]') },
      div({ class: css('carbon-bubble-user _p3 _r2 _rtr0') },
        div({ class: css('_prose') }, message.content)
      ),
      time({ class: css('_textsm _fgmuted _tr') }, message.timestamp)
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Avatar, Button, icon } from 'decantr/components';

code.example:
function AssistantMessage({ message, onCopy, onReact }) {
  const { div, span, time } = tags;
  const [showActions, setShowActions] = createSignal(false);

  return div({ 
    class: css('_flex _jcs _gap3 _py2'),
    onmouseenter: () => setShowActions(true),
    onmouseleave: () => setShowActions(false)
  },
    Avatar({ src: '/ai-avatar.svg', size: 'sm', class: css('_shrink0') }),
    div({ class: css('_flex _col _gap1 _maxw[70%]') },
      div({ class: css('carbon-bubble-ai _p3 _r2 _rtl0') },
        div({ class: css('_prose') }, message.content)
      ),
      div({ class: css('_flex _aic _gap2') },
        time({ class: css('_textsm _fgmuted') }, message.timestamp),
        showActions() ? div({ class: css('_flex _gap1') },
          Button({ variant: 'ghost', size: 'xs', onclick: onCopy }, icon('copy', { size: '14' })),
          Button({ variant: 'ghost', size: 'xs', onclick: onReact }, icon('smile', { size: '14' }))
        ) : null
      )
    )
  );
}

function SystemMessage({ message }) {
  const { div, span } = tags;

  return div({ class: css('_flex _jcc _py2') },
    span({ class: css('_textsm _fgmuted _bgmuted/10 _px3 _py1 _rfull') },
      message.content
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Avatar, Button, icon } from 'decantr/components';

code.example:
function ChatMessage({ message, variant = 'assistant' }) {
  const { div } = tags;

  if (variant === 'user') return UserMessage({ message });
  if (variant === 'system') return SystemMessage({ message });
  return AssistantMessage({ message });
}
